static void writeFileOrStdout(llvm::StringRef path, llvm::StringRef text) {
  if (path.empty() || path == "-") {
    llvm::outs() << text;
    return;
  }
  std::error_code ec;
  llvm::raw_fd_ostream os(path, ec, llvm::sys::fs::OF_Text);
  if (ec) {
    llvm::errs() << "cannot open report file " << path << ": " << ec.message() << "\n";
    return;
  }
  os << text;
}

static std::string jsonEscape(llvm::StringRef s) {
  std::string out;
  for (char c : s) {
    switch (c) {
    case '"': out += "\\\""; break;
    case '\\': out += "\\\\"; break;
    case '\n': out += "\\n"; break;
    case '\r': out += "\\r"; break;
    case '\t': out += "\\t"; break;
    default: out += c; break;
    }
  }
  return out;
}

static void registerDialects(DialectRegistry &registry) {
#ifdef TRITONSIM_HAS_BISHENGIR_HIVM
  registry.insert<mlir::hivm::HIVMDialect>();
  registry.insert<mlir::annotation::AnnotationDialect>();
  registry.insert<mlir::hacc::HACCDialect>();
#endif
  registry.insert<arith::ArithDialect>();
  registry.insert<func::FuncDialect>();
  registry.insert<memref::MemRefDialect>();
  registry.insert<scf::SCFDialect>();
  registry.insert<tensor::TensorDialect>();
  registry.insert<mlir::bufferization::BufferizationDialect>();
}

