struct DryRunAction {
  std::string actionId;
  std::string mutationKind;
  std::string eventId;
  std::string setPipe;
  std::string waitPipe;
  int targetLine = -1;
  std::vector<int> candidateLines;
};

static std::string readTextFileBestEffort(llvm::StringRef path) {
  if (path.empty()) return "";
  std::ifstream in{std::string(path)};
  if (!in) return "";
  std::ostringstream ss;
  ss << in.rdbuf();
  return ss.str();
}

static std::string regexFirst(const std::string &text, const std::regex &rx) {
  std::smatch m;
  if (std::regex_search(text, m, rx) && m.size() >= 2) return m[1].str();
  return "";
}

static std::vector<int> regexAllInts(const std::string &text, const std::regex &rx) {
  std::vector<int> out;
  auto begin = std::sregex_iterator(text.begin(), text.end(), rx);
  auto end = std::sregex_iterator();
  for (auto it = begin; it != end; ++it) {
    try { out.push_back(std::stoi((*it)[1].str())); } catch (...) {}
  }
  return out;
}

static std::vector<DryRunAction> parseEditScriptActionsBestEffort(const std::string &text) {
  std::vector<DryRunAction> out;
  if (text.empty()) return out;
  std::regex actionRx("\\\"action_id\\\"\\s*:\\s*\\\"([^\\\"]+)\\\"");
  auto begin = std::sregex_iterator(text.begin(), text.end(), actionRx);
  auto end = std::sregex_iterator();
  std::vector<std::pair<size_t, std::string>> ids;
  for (auto it = begin; it != end; ++it) ids.push_back({(size_t)it->position(), (*it)[1].str()});
  for (size_t i = 0; i < ids.size(); ++i) {
    size_t start = ids[i].first;
    size_t stop = (i + 1 < ids.size()) ? ids[i + 1].first : text.size();
    std::string win = text.substr(start, stop - start);
    DryRunAction a;
    a.actionId = ids[i].second;
    a.mutationKind = regexFirst(win, std::regex("\\\"mutation_kind\\\"\\s*:\\s*\\\"([^\\\"]+)\\\""));
    a.eventId = regexFirst(win, std::regex("\\\"event_id\\\"\\s*:\\s*\\\"([^\\\"]+)\\\""));
    a.setPipe = regexFirst(win, std::regex("\\\"set_pipe\\\"\\s*:\\s*\\\"?([^\\\",}]+)\\\"?"));
    a.waitPipe = regexFirst(win, std::regex("\\\"wait_pipe\\\"\\s*:\\s*(?:\\\"([^\\\"]+)\\\"|null)"));
    if (a.waitPipe.empty()) a.waitPipe = a.setPipe;
    if (a.eventId.empty()) {
      std::smatch em;
      std::regex aidEvent("sync_check_event_([A-Za-z0-9_]+)");
      if (std::regex_search(a.actionId, em, aidEvent) && em.size() >= 2) a.eventId = em[1].str();
    }
    a.candidateLines = regexAllInts(win, std::regex("\\\"line\\\"\\s*:\\s*([0-9]+)"));
    if (!a.candidateLines.empty()) a.targetLine = a.candidateLines.front();
    out.push_back(a);
  }
  return out;
}

